import Mathlib

-- Define language concatenation
def language_concatenation {α : Type*} (L1 L2 : Set (List α)) : Set (List α) :=
  {w : List α | ∃ (u v : List α), w = u ++ v ∧ u ∈ L1 ∧ v ∈ L2}

-- Auxiliary lemma: length of concatenated list is sum of lengths
theorem length_concat_eq_length_add_leng

